// LESSON: JavaFX Events and Properties - Reference Page 2.
// You will learn: Handle actions, listeners, binding, and property updates.
import javafx.application.Application;
import javafx.beans.property.IntegerProperty;
import javafx.beans.property.SimpleIntegerProperty;
import javafx.geometry.Insets;
import javafx.scene.Scene;
import javafx.scene.control.Button;
import javafx.scene.control.Label;
import javafx.scene.control.Slider;
import javafx.scene.control.TextField;
import javafx.scene.layout.VBox;
import javafx.stage.Stage;

public class JavaFxEventsPropertiesReference extends Application {
  public static void main(String[] args) {
    launch(args);
  }

  @Override
  public void start(Stage stage) {
    VBox root = new VBox(10);
    root.setPadding(new Insets(12));
    root.getChildren().addAll(actionEventExample(), listenerExample(), bindingExample());
    stage.setScene(new Scene(root, 460, 320));
    stage.setTitle("Events and properties");
    stage.show();
  }

  private VBox actionEventExample() {
    IntegerProperty clicks = new SimpleIntegerProperty(0);
    Label counter = new Label();
    counter.textProperty().bind(clicks.asString("EXAMPLE 1: Clicks: %d"));
    Button button = new Button("Click");
    button.setOnAction(e -> clicks.set(clicks.get() + 1));
    return new VBox(5, counter, button);
  }

  private VBox listenerExample() {
    TextField input = new TextField();
    Label mirror = new Label("EXAMPLE 2: Type something");
    input.textProperty().addListener((obs, oldText, newText) -> mirror.setText("Text: " + newText));
    return new VBox(5, mirror, input);
  }

  private VBox bindingExample() {
    Slider slider = new Slider(0, 100, 50);
    Label value = new Label();
    value.textProperty().bind(slider.valueProperty().asString("EXAMPLE 3: Value: %.0f"));
    return new VBox(5, value, slider);
  }
}
